const body = $input.first().json.body || $input.first().json;
const newStatus = (
  body.history_items?.[0]?.after?.status ||
  body.task?.status?.status || ''
).toLowerCase().trim();

const taskId = body.task_id || body.task?.id || '';
const isAguardando = newStatus === 'aguardando assinatura';

return [{ json: { prosseguir: isAguardando && taskId !== '', taskId, newStatus } }];

const task = $input.first().json;
const cf = task.custom_fields || [];

function getVal(id) {
  const f = cf.find(x => x.id === id);
  if (!f || f.value == null) return '';
  if (f.type_config?.options) {
    const opt = f.type_config.options.find(o => o.orderindex === f.value || o.id === f.value);
    return opt?.name || String(f.value);
  }
  if (f.type === 'date') return f.value ? new Date(parseInt(f.value)).toLocaleDateString('pt-BR') : '';
  if (f.type === 'currency') return 'R$ ' + (parseFloat(f.value)/100).toLocaleString('pt-BR',{minimumFractionDigits:2});
  return String(f.value).trim();
}

const now = new Date();
const brt = new Date(now.getTime() - 3*3600000);
const dtBRT = brt.toLocaleString('pt-BR', {timeZone:'UTC'});

